        environ.update(self.env)

    popen_kwargs: dict[str, t.Any] = {}

    if WIN and self.process_priority in _WINDOWS_PRIORITY_CLASSES:
        popen_kwargs["creationflags"] = _WINDOWS_PRIORITY_CLASSES[
            self.process_priority
        ]

    try:
        c = subprocess.Popen(
            f'{editor} "{filename}"', env=environ, shell=True, **popen_kwargs
        )

        if not WIN and self.process_priority in _POSIX_NICE_VALUES:
            try:
                os.setpriority(
                    os.PRIO_PROCESS,
